// Some portions generated by Claude
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.concurrent.TimeUnit;

import org.eclipse.rdf4j.sail.lmdb.evaluation.codegen.JaninoKernel;
import org.eclipse.rdf4j.sail.lmdb.evaluation.codegen.KernelContext;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Milestone-2 infrastructure tests for {@link LmdbNativeJaninoCodegen}: async compile + admission threshold, cache
 * hits, compile-failure fallback without retry storms, entry-limit eviction, and source dumping.
 */
public class LmdbNativeJaninoCodegenTest {

	private static final String KERNEL_CLASS = "org.eclipse.rdf4j.sail.lmdb.gen.M2TestKernel";
	private static final String KERNEL_SOURCE = "package org.eclipse.rdf4j.sail.lmdb.gen;\n"
			+ "public final class M2TestKernel implements org.eclipse.rdf4j.sail.lmdb.evaluation.codegen.JaninoKernel {\n"
			+ "    private long constant;\n"
			+ "    private boolean done;\n"
			+ "    public void bind(org.eclipse.rdf4j.sail.lmdb.evaluation.codegen.KernelContext context) {\n"
			+ "        constant = context.constants[0];\n"
			+ "    }\n"
			+ "    public int fill(long[] rowBuffer, int maxRows) {\n"
			+ "        if (done || maxRows < 1) { return 0; }\n"
			+ "        rowBuffer[0] = constant;\n"
			+ "        done = true;\n"
			+ "        return 1;\n"
			+ "    }\n"
			+ "}\n";

	private final Object owner = new Object();
	private String previousEnabled;
	private String previousThreshold;
	private String previousMaxEntries;
	private String previousDumpDir;

	@BeforeEach
	public void setUp() {
		previousEnabled = System.getProperty(LmdbNativeJaninoCodegen.ENABLED_PROPERTY);
		previousThreshold = System.getProperty(LmdbNativeJaninoCodegen.THRESHOLD_ROWS_PROPERTY);
		previousMaxEntries = System.getProperty(LmdbNativeJaninoCodegen.MAX_ENTRIES_PROPERTY);
		previousDumpDir = System.getProperty(LmdbNativeJaninoCodegen.DUMP_DIR_PROPERTY);
		System.setProperty(LmdbNativeJaninoCodegen.ENABLED_PROPERTY, "true");
		System.setProperty(LmdbNativeJaninoCodegen.THRESHOLD_ROWS_PROPERTY, "0");
		LmdbNativeJaninoCodegen.resetForTests();
	}

	@AfterEach
	public void tearDown() {
		restore(LmdbNativeJaninoCodegen.ENABLED_PROPERTY, previousEnabled);
		restore(LmdbNativeJaninoCodegen.THRESHOLD_ROWS_PROPERTY, previousThreshold);
		restore(LmdbNativeJaninoCodegen.MAX_ENTRIES_PROPERTY, previousMaxEntries);
		restore(LmdbNativeJaninoCodegen.DUMP_DIR_PROPERTY, previousDumpDir);
		LmdbNativeJaninoCodegen.resetForTests();
	}

	private static void restore(String key, String previous) {
		if (previous == null) {
			System.clearProperty(key);
		} else {
			System.setProperty(key, previous);
		}
	}

	private JaninoKernel awaitKernel(String shapeKey) throws InterruptedException {
		JaninoKernel first = LmdbNativeJaninoCodegen.kernel(owner, shapeKey, KERNEL_CLASS, () -> KERNEL_SOURCE, 1L);
		if (first != null) {
			return first;
		}
		return LmdbNativeJaninoCodegen.awaitKernel(owner, shapeKey, 30, TimeUnit.SECONDS);
	}

	@Test
	public void compilesBindsAndFills() throws Exception {
		JaninoKernel kernel = awaitKernel("shape-basic");
		assertNotNull(kernel);
		kernel.bind(new KernelContext(null, new long[] { 42L }, null, null));
		long[] buffer = new long[4];
		assertEquals(1, kernel.fill(buffer, 4));
		assertEquals(42L, buffer[0]);
		assertEquals(0, kernel.fill(buffer, 4));
		kernel.close();
		assertEquals(1L, LmdbNativeJaninoCodegen.COMPILATIONS.get());
	}

	@Test
	public void disabledAndBelowThresholdReturnNull() {
		System.setProperty(LmdbNativeJaninoCodegen.ENABLED_PROPERTY, "false");
		assertNull(LmdbNativeJaninoCodegen.kernel(owner, "shape-off", KERNEL_CLASS, () -> KERNEL_SOURCE, 1L));
		System.setProperty(LmdbNativeJaninoCodegen.ENABLED_PROPERTY, "true");
		System.setProperty(LmdbNativeJaninoCodegen.THRESHOLD_ROWS_PROPERTY, "1000");
		assertNull(LmdbNativeJaninoCodegen.kernel(owner, "shape-cold", KERNEL_CLASS, () -> KERNEL_SOURCE, 999L));
		assertEquals(0L, LmdbNativeJaninoCodegen.COMPILATIONS.get());
		assertEquals(0L, LmdbNativeJaninoCodegen.CACHE_MISSES.get());
	}

	@Test
	public void cacheHitsOnSubsequentCalls() throws Exception {
		assertNotNull(awaitKernel("shape-cache"));
		JaninoKernel second = LmdbNativeJaninoCodegen.kernel(owner, "shape-cache", KERNEL_CLASS, () -> {
			throw new AssertionError("source supplier must not run on a cache hit");
		}, 1L);
		assertNotNull(second);
		assertEquals(1L, LmdbNativeJaninoCodegen.COMPILATIONS.get());
		assertTrue(LmdbNativeJaninoCodegen.CACHE_HITS.get() >= 1L);
		assertTrue(LmdbNativeJaninoCodegen.KERNEL_INSTANTIATIONS.get() >= 2L);
	}

	@Test
	public void compileFailureFallsBackAndDoesNotRetry() throws Exception {
		String badSource = "package org.eclipse.rdf4j.sail.lmdb.gen; public final class Broken { this is not java }";
		assertNull(LmdbNativeJaninoCodegen.kernel(owner, "shape-broken", "org.eclipse.rdf4j.sail.lmdb.gen.Broken",
				() -> badSource, 1L));
		assertNull(LmdbNativeJaninoCodegen.awaitKernel(owner, "shape-broken", 30, TimeUnit.SECONDS));
		assertEquals(1L, LmdbNativeJaninoCodegen.COMPILE_FAILURES.get());
		// A later call for the same shape must not schedule a second compile.
		assertNull(LmdbNativeJaninoCodegen.kernel(owner, "shape-broken", "org.eclipse.rdf4j.sail.lmdb.gen.Broken",
				() -> badSource, 1L));
		assertEquals(1L, LmdbNativeJaninoCodegen.COMPILE_FAILURES.get());
		assertEquals(0L, LmdbNativeJaninoCodegen.COMPILATIONS.get());
		assertTrue(LmdbNativeJaninoCodegen.FALLBACKS.get() >= 2L);
	}

	@Test
	public void evictsBeyondEntryLimit() throws Exception {
		System.setProperty(LmdbNativeJaninoCodegen.MAX_ENTRIES_PROPERTY, "2");
		assertNotNull(awaitKernel("shape-1"));
		assertNotNull(awaitKernel("shape-2"));
		assertNotNull(awaitKernel("shape-3"));
		assertTrue(LmdbNativeJaninoCodegen.EVICTIONS.get() >= 1L);
	}

	@Test
	public void dumpsGeneratedSource(@TempDir Path dumpDir) throws Exception {
		System.setProperty(LmdbNativeJaninoCodegen.DUMP_DIR_PROPERTY, dumpDir.toString());
		assertNotNull(awaitKernel("shape-dump"));
		Path dumped = dumpDir.resolve("M2TestKernel.java");
		assertTrue(Files.exists(dumped), "expected dumped source at " + dumped);
		assertTrue(Files.readString(dumped).contains("class M2TestKernel"));
	}
}
